  addPolygonsToMap() {
    // Add a check to ensure map is defined before proceeding
    if (!this.map) {
      console.warn('Map not ready yet. Cannot add polygons.');
      return;
    }

    this.states_dict.forEach(stateObj => {
      (Object.keys(stateObj) as Array<keyof typeof stateObj>).forEach(stateName => {
        const coordinates = stateObj[stateName];

        const transformedCoordinates = coordinates.map((polygonCoords: any) => {
            // Check if polygonCoords is an array of coordinate pairs or an array of rings
            if (Array.isArray(polygonCoords) && typeof polygonCoords[0][0] === 'number') {
                // It's a linear ring (e.g., GeoLinearRing)
                return polygonCoords.map((coordPair: number[]) => [coordPair[1], coordPair[0]]);
            } else if (Array.isArray(polygonCoords) && Array.isArray(polygonCoords[0]) && typeof polygonCoords[0][0] === 'number') {
                // It's a GeoPolygon (array of linear rings)
                return polygonCoords.map((linearRing: number[][]) =>
                    linearRing.map((coordPair: number[]) => [coordPair[1], coordPair[0]])
                );
            }
            // Handle more complex or unexpected structures if necessary, or throw an error
            return polygonCoords; // Fallback, though a type-safe approach would avoid this
        });


        // Determine if it's a simple polygon or a multipolygon based on nesting
        // Now, we're working with transformedCoordinates where inner arrays are [lat, lng]
        // This check needs to be adjusted based on the `StateBoundaryData` transformation
        if (typeof transformedCoordinates[0][0][0] === 'number') {
          // This would be a GeoMultiPolygon after transformation: [[[[lat,lng]]]]
          transformedCoordinates.forEach((polyArray: any) => {
            if (Array.isArray(polyArray[0]) && typeof polyArray[0][0] === 'number') {
                const polygon = L.polygon(polyArray as L.LatLngExpression[], { color: 'blue' }).addTo(this.map as L.Map);
                polygon.bindPopup(`<b>${stateName}</b>`);
            } else {
                 // It's a GeoPolygon after transformation: [[[lat,lng]]]
                 const polygon = L.polygon(polyArray as L.LatLngExpression[][], { color: 'blue' }).addTo(this.map as L.Map);
                 polygon.bindPopup(`<b>${stateName}</b>`);
            }
          });
        } else {
            // This would be a GeoPolygon after transformation: [[[lat,lng]]]
            const polygon = L.polygon(transformedCoordinates as L.LatLngExpression[][], { color: 'blue' }).addTo(this.map as L.Map);
            polygon.bindPopup(`<b>${stateName}</b>`);
        }
      });
    });
  }
